// Define display list
glNewList(1, GL_COMPILE);
 glColor3f(1.0, 0.0, 0.0); // Red color
 glBegin(GL_QUADS);
 glVertex2f(-1.0, -1.0);
 glVertex2f(1.0, -1.0);
 glVertex2f(1.0, 1.0);
 glVertex2f(-1.0, 1.0);
 glEnd();
glEndList();

// Execute display list multiple times
glCallList(1); // First instance

// Translate and draw again
glTranslatef(3.0, 0.0, 0.0);
glCallList(1); // Second instance

// Draw robot arm with hierarchical structure
void drawArm() {
 // Base
 glPushMatrix();
 glTranslatef(0.0, -2.0, 0.0);
 drawCylinder();

 // Upper arm
 glPushMatrix();
 glTranslatef(0.0, 1.0, 0.0);
 glRotatef(armAngle, 0.0, 0.0, 1.0);
 drawBox(0.3, 2.0, 0.3);

 // Forearm
 glPushMatrix();
 glTranslatef(0.0, 1.0, 0.0);
 glRotatef(forearmAngle, 0.0, 0.0, 1.0);
 drawBox(0.2, 1.5, 0.2);

 // Hand
 glPushMatrix();
 glTranslatef(0.0, 0.75, 0.0);
 drawSphere(0.3);
 glPopMatrix();
 glPopMatrix();
 glPopMatrix();
 glPopMatrix();
}

// Example 1: Translation
glLoadIdentity();
glTranslatef(2.0, 1.0, 0.0); // Move 2 units right, 1 up
drawObject();

// Example 2: Rotation
glLoadIdentity();
glRotatef(45.0, 0.0, 0.0, 1.0); // 45° around Z-axis
drawObject();

// Example 3: Scaling
glLoadIdentity();
glScalef(2.0, 0.5, 1.0); // 2x width, 0.5x height
drawObject();

// Example 4: Combined (T then R then S)
glLoadIdentity();
glTranslatef(1.0, 0.0, 0.0); // Apply 3rd
glRotatef(45.0, 0.0, 0.0, 1.0); // Apply 2nd
glScalef(2.0, 1.0, 1.0); // Apply 1st (closest to object)
drawObject();

// Create multiple display lists for different shapes
void createShapeLists() {
 // List 1: Triangle
 glNewList(1, GL_COMPILE);
 glBegin(GL_TRIANGLES);
 glVertex2f(0.0, 1.0);
 glVertex2f(-1.0, -1.0);
 glVertex2f(1.0, -1.0);
 glEnd();
 glEndList();

 // List 2: Square
 glNewList(2, GL_COMPILE);
 glBegin(GL_QUADS);
 glVertex2f(-1.0, 1.0);
 glVertex2f(1.0, 1.0);
 glVertex2f(1.0, -1.0);
 glVertex2f(-1.0, -1.0);
 glEnd();
 glEndList();

 // List 3: Pentagon
 glNewList(3, GL_COMPILE);
 // Pentagon vertices...
 glEndList();
}

// Call multiple lists
GLuint listIDs[] = {1, 2, 3, 1, 2};
glCallLists(5, GL_UNSIGNED_INT, listIDs);
